final:
module RefModule(
    input clk,
    input rst,
    input en,
    output reg [3:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) 
        count <= 4'd0;
    else if (en)
        count <= (count == 4'd15) ? 4'd0 : count + 1;
end

endmodule
